SELECT COUNT(*)
FROM ethnic_groups
WHERE eligible_rate > 0.1;

SELECT eg.ethnicity, (eg.population - pd.panel_size) AS population_difference
FROM ethnic_groups eg
INNER JOIN panel_data pd ON eg.ethnicity_id = pd.ethnicity_id;

SELECT panel_name, panel_description
FROM panel_data
WHERE panel_id = 1;

SELECT ethnicity AS Highest_Population_Ethnicity
FROM ethnic_groups
WHERE population = (SELECT MAX(population) FROM ethnic_groups);

SELECT u.username, r.summary 
FROM users u 
INNER JOIN reports r ON u.username = r.generated_by;

SELECT ethnicity_id
FROM panel_data
WHERE panel_name = 'Diversity Committee';

SELECT MAX(report_date) AS most_recent_report_date
FROM reports
WHERE generated_by = (SELECT user_id FROM users WHERE username = 'johndoe');
